VALUES
  ('heelevel3-53250add-moex-00022', 'heelevel3-53250add', 'heelevel3-53250add-moex-114-9b7ab1bb', 'sub-heelevel3-53250add-02', NULL, 'single_choice', '下列關於普通地上權存續期間規定之敘述，何者正確？', '["定有期限之地上權，為達土地利用目的，其存續期間不得低於一年以下", "定有期限之地上權，其存續期間逾三十年者，縮短為三十年", "未定有期限之地上權，其存續期間逾二十年者，當事人一方得自行終止其地上權", "未定有期限之地上權，如係以公共建設為目的而成立者，以該建設使用目的完畢時，視為地上 權之存續期限 23520"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:03+00:00", "source_pdf_sha1": "7894a239bcc1", "answer_pdf_sha1": "b00f4253350b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "235", "s": "0904", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "智慧財產行政"}'::jsonb, NULL),
  ('heelevel3-53250add-moex-00023', 'heelevel3-53250add', 'heelevel3-53250add-moex-114-9b7ab1bb', 'sub-heelevel3-53250add-02', NULL, 'single_choice', '下列何者非為民法上之物權？', '["不動產役權", "典權", "權利質權", "遺產之使用收益權"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:03+00:00", "source_pdf_sha1": "7894a239bcc1", "answer_pdf_sha1": "b00f4253350b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "235", "s": "0904", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "智慧財產行政"}'::jsonb, NULL),
  ('heelevel3-53250add-moex-00024', 'heelevel3-53250add', 'heelevel3-53250add-moex-114-9b7ab1bb', 'sub-heelevel3-53250add-02', NULL, 'single_choice', '下列關於不動產所有權之取得或移轉，何者應辦理登記，始發生效力？', '["私人土地之徵收", "法院強制執行拍賣債務人名下之土地，而由他人拍定", "私人拋棄其土地所有權", "私人蓋好房屋"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:03+00:00", "source_pdf_sha1": "7894a239bcc1", "answer_pdf_sha1": "b00f4253350b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "235", "s": "0904", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "智慧財產行政"}'::jsonb, NULL),
  ('heelevel3-53250add-moex-00025', 'heelevel3-53250add', 'heelevel3-53250add-moex-114-9b7ab1bb', 'sub-heelevel3-53250add-02', NULL, 'single_choice', '甲男乙女為夫妻，甲竟與乙之姪女丙發生姦情。乙訴請判決離婚，判決確定之一個月後，甲與丙 結婚。下列敘述，何者正確？', '["甲丙違反待婚期間之限制，其婚姻得撤銷", "甲丙違反相姦婚禁止之規定，其婚姻得撤銷", "甲丙違反近親結婚之限制，其婚姻無效", "甲丙並未違反規定，其婚姻有效"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:03+00:00", "source_pdf_sha1": "7894a239bcc1", "answer_pdf_sha1": "b00f4253350b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "235", "s": "0904", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "智慧財產行政"}'::jsonb, NULL),
  ('heelevel3-53250add-moex-00026', 'heelevel3-53250add', 'heelevel3-53250add-moex-114-9b7ab1bb', 'sub-heelevel3-53250add-02', NULL, 'single_choice', '遺產分割後，其未清償之被繼承人之債務，移歸一定之人承受，或劃歸各繼承人分擔，如經債權 人同意者，各繼承人得免除何種責任？', '["連帶保證", "連帶責任", "連帶債權", "侵權責任"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:03+00:00", "source_pdf_sha1": "7894a239bcc1", "answer_pdf_sha1": "b00f4253350b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "235", "s": "0904", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "智慧財產行政"}'::jsonb, NULL),
  ('heelevel3-53250add-moex-00027', 'heelevel3-53250add', 'heelevel3-53250add-moex-114-9b7ab1bb', 'sub-heelevel3-53250add-02', NULL, 'single_choice', '甲、乙為夫妻，無子女。甲之父母均已死亡，甲有兄弟丙、丁二人。甲生前曾向丙借款新臺幣（下 同）40萬元，尚未清償。甲死亡時，留有遺產200萬元。遺產分割時，丙可分得多少財產？', '["60萬元", "70萬元", "80萬元", "90萬元"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:03+00:00", "source_pdf_sha1": "7894a239bcc1", "answer_pdf_sha1": "b00f4253350b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "235", "s": "0904", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "智慧財產行政"}'::jsonb, NULL),
  ('heelevel3-53250add-moex-00028', 'heelevel3-53250add', 'heelevel3-53250add-moex-114-9b7ab1bb', 'sub-heelevel3-53250add-02', NULL, 'single_choice', '甲男乙女於民國112年1月間結婚，甲於結婚前，有勞力所得新臺幣（下同）60萬元。下列關於 夫妻財產之敘述，何者正確？', '["設甲乙約定採共同財產制，甲勞力所得之60萬元，由甲乙分別共有", "設甲乙約定採分別財產制，甲勞力所得之60萬元，由甲乙分別共有", "設甲乙未約定夫妻財產制，甲勞力所得之60萬元，由甲乙公同共有", "設甲乙約定採勞力所得共同財產制，甲勞力所得之60萬元，由甲單獨所有"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:03+00:00", "source_pdf_sha1": "7894a239bcc1", "answer_pdf_sha1": "b00f4253350b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "235", "s": "0904", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "智慧財產行政"}'::jsonb, NULL),
  ('heelevel3-53250add-moex-00029', 'heelevel3-53250add', 'heelevel3-53250add-moex-114-9b7ab1bb', 'sub-heelevel3-53250add-02', NULL, 'single_choice', '未婚之甲女與乙男發生性關係後懷孕並產下丙。丙成年後找到乙，要求乙為認領。乙表示其生活 窮困，若丙願扶養，則乙願認領。下列敘述，何者正確？', '["認領後，如丙確有受扶養必要，乙有扶養能力，乙應扶養丙", "認領後，如乙確實無謀生能力但尚非無法維持生活，丙仍應扶養乙", "認領後，如乙確有受扶養必要，甲丙應共同扶養乙", "認領經雙方意思表示合致成立，乙所附條件為有效"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:03+00:00", "source_pdf_sha1": "7894a239bcc1", "answer_pdf_sha1": "b00f4253350b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "235", "s": "0904", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "智慧財產行政"}'::jsonb, NULL),
  ('heelevel3-53250add-moex-00030', 'heelevel3-53250add', 'heelevel3-53250add-moex-114-9b7ab1bb', 'sub-heelevel3-53250add-02', NULL, 'single_choice', '甲乙為夫妻，生有A、B二子，並收養C為養女。乙於民國108年間死亡。今甲死亡，下列敘述， 何者正確？', '["A如對甲有重大之虐待或侮辱情事，經B及C共同表示A不得繼承；A則喪失其對甲之繼承權", "A及B於乙死亡後，否認C之繼承資格，並排除其對繼承財產之占有，C自知悉其得繼承之 時起2年間，得行使遺產酌給請求權", "B如有以詐欺或脅迫，使甲為關於繼承遺囑之情事，B則喪失其對甲之繼承權。但經甲宥恕者， 其繼承權不喪失", "甲如未立遺囑，C之應繼分為甲遺產之五分之一，A及B之應繼分各為甲遺產之五分之二"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:03+00:00", "source_pdf_sha1": "7894a239bcc1", "answer_pdf_sha1": "b00f4253350b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "235", "s": "0904", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "智慧財產行政"}'::jsonb, NULL),
  ('heelevel3-53250add-moex-00031', 'heelevel3-53250add', 'heelevel3-53250add-moex-114-3082b5f1', 'sub-heelevel3-53250add-03', NULL, 'essay', '甲之先人遺留 A洋樓經 T縣政府指定為縣定古蹟。T縣政府核定補助 A
洋樓修復再利用案後，擬與所有人甲締結「A洋樓修復再利用補助行政
契約」。雙方經多次協商後，就履約標的、補助金額、補助內容（含修復
計畫）、撥款方式、履約管理、違約責任、爭議處理等雙方權利義務重要
事項陸續達成共識，且均有往來書面文件及會議紀錄為憑。雙方關於撥
款之約定為第一期款於甲辦理工程招標後，撥付補助款 50%。甲遂於工
程招標後檢附工程契約向 T縣政府請求撥付補助金額新臺幣（以下同）
1 千萬元之 50%，即 500 萬元款項。T 縣政府拒絕，表示補助行政契約
尚未完成簽署，契約並未成立。T縣政府之主張是否有理由？假設 T縣
政府向該管高等行政法院起訴，請求「確認 A洋樓修復再利用補助行政
契約不存在」，其起訴是否合法？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:03+00:00", "source_pdf_sha1": "1959a582ef2c", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "235", "s": "0404", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "智慧財產行政"}'::jsonb, NULL)
